class Solution:
    def countOfPeaks(self, nums, queries):
        nums = list(nums)
        result = []
        def is_peak(i):
            return 0 < i < len(nums) - 1 and nums[i] > nums[i-1] and nums[i] > nums[i+1]
        for q in queries:
            if q[0] == 1:
                l, r = q[1], q[2]
                count = sum(1 for i in range(l + 1, r) if is_peak(i))
                result.append(count)
            else:
                nums[q[1]] = q[2]
        return result

