class Solution:
    def countOfPeaks(self, nums, queries):
        n = len(nums)
        nums = list(nums)
        # Fenwick tree over peak flags at indices 1..n-2
        bit = [0] * (n + 1)
        def update(i, delta):
            i += 1  # 1-indexed
            while i <= n:
                bit[i] += delta
                i += i & (-i)
        def query(i):
            i += 1
            s = 0
            while i > 0:
                s += bit[i]
                i -= i & (-i)
            return s
        def range_query(l, r):
            if l > r:
                return 0
            return query(r) - (query(l - 1) if l > 0 else 0)
        def is_peak(i):
            return 0 < i < n - 1 and nums[i] > nums[i-1] and nums[i] > nums[i+1]
        # Initialize BIT
        for i in range(1, n - 1):
            if is_peak(i):
                update(i, 1)
        result = []
        for q in queries:
            if q[0] == 1:
                l, r = q[1], q[2]
                # peaks can only exist at indices l+1 .. r-1
                if r - l < 2:
                    result.append(0)
                else:
                    result.append(range_query(l + 1, r - 1))
            else:
                idx, val = q[1], q[2]
                # Recompute peak flags for affected positions
                affected = [idx - 1, idx, idx + 1]
                old_peaks = {i: is_peak(i) for i in affected if 0 < i < n - 1}
                nums[idx] = val
                for i in affected:
                    if 0 < i < n - 1:
                        new_pk = is_peak(i)
                        if old_peaks.get(i, False) != new_pk:
                            update(i, 1 if new_pk else -1)
        return result

