var countOfPeaks = function(nums, queries) {
    const n = nums.length;
    nums = [...nums];
    const bit = new Int32Array(n + 1);
    function update(i, delta) {
        for (i++; i <= n; i += i & (-i)) bit[i] += delta;
    }
    function query(i) {
        let s = 0;
        for (i++; i > 0; i -= i & (-i)) s += bit[i];
        return s;
    }
    function rangeQ(l, r) {
        if (l > r) return 0;
        return query(r) - (l > 0 ? query(l - 1) : 0);
    }
    function isPeak(i) {
        return i > 0 && i < n - 1 && nums[i] > nums[i-1] && nums[i] > nums[i+1];
    }
    for (let i = 1; i < n - 1; i++) {
        if (isPeak(i)) update(i, 1);
    }
    const result = [];
    for (const q of queries) {
        if (q[0] === 1) {
            const [, l, r] = q;
            result.push(r - l < 2 ? 0 : rangeQ(l + 1, r - 1));
        } else {
            const [, idx, val] = q;
            const affected = [idx - 1, idx, idx + 1];
            const oldPeaks = {};
            for (const i of affected) {
                if (i > 0 && i < n - 1) oldPeaks[i] = isPeak(i);
            }
            nums[idx] = val;
            for (const i of affected) {
                if (i > 0 && i < n - 1) {
                    const np = isPeak(i);
                    if (oldPeaks[i] !== np) update(i, np ? 1 : -1);
                }
            }
        }
    }
    return result;
};
